import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useCart } from '../../context/CartContext';
import '../../assets/styles/Collection.css';

const Collection = () => {
  const { addToCart } = useCart();
  const navigate = useNavigate();

  const collectionProducts = {
    'desi-ghee': {
      id: 'desi-ghee',
      title: 'Sona Desi Ghee',
      price: 1250,
      image: '/images/desi-ghee.png',
      weight: '1000ml'
    },
    'kaju-jaggery': {
      id: 'kaju-jaggery',
      title: 'Kaju Jaggery',
      price: 550,
      image: '/images/kaju-jaggery.png',
      weight: '500g'
    },
    'desi-gud': {
      id: 'desi-gud',
      title: 'Desi Gud',
      price: 320,
      image: '/images/desi-gud.png',
      weight: '1kg'
    },
    'jaggery-powder': {
      id: 'jaggery-powder',
      title: 'Jaggery Powder',
      price: 280,
      image: '/images/jaggery-powder.png',
      weight: '500g'
    }
  };

  const handleQuickAdd = async (e, key) => {
    e.preventDefault();
    e.stopPropagation();
    const product = collectionProducts[key];
    await addToCart({
      productId: product.id,
      title: product.title,
      price: product.price,
      image: product.image,
      weight: product.weight,
      quantity: 1
    });
  };

  const handleBuyNow = async (e, key) => {
    e.preventDefault();
    e.stopPropagation();
    const product = collectionProducts[key];
    await addToCart({
      productId: product.id,
      title: product.title,
      price: product.price,
      image: product.image,
      weight: product.weight,
      quantity: 1
    });
    navigate('/checkout');
  };

  return (
    <section className="collection-section">
      <div className="collection-header">
        <h2 className="collection-title">The Atelier Collection</h2>
        <div className="collection-divider"></div>
      </div>

      <div className="collection-grid">
        {/* Large Card Layout */}
        <Link to="/product/desi-ghee" className="collection-card card-large" style={{ textDecoration: 'none' }}>
          <img src="/images/desi-ghee.png" alt="Desi Ghee" className="collection-img" />
          <div className="collection-text-overlay">
            <div className="overlay-info">
              <h3>Sona Desi Ghee</h3>
              <p>From happy A2 cows</p>
            </div>
            <div className="overlay-actions">
              <button className="coll-btn-cart" onClick={(e) => handleQuickAdd(e, 'desi-ghee')}>+ Cart</button>
              <button className="coll-btn-buy" onClick={(e) => handleBuyNow(e, 'desi-ghee')}>Buy Now</button>
            </div>
          </div>
        </Link>

        {/* Small Cards */}
        <Link to="/product/kaju-jaggery" className="collection-card kaju" style={{ textDecoration: 'none' }}>
          <img src="/images/kaju-jaggery.png" alt="Kaju Jaggery" className="collection-img" />
          <div className="collection-text-overlay">
            <div className="overlay-info">
              <h3>Kaju Jaggery</h3>
              <p>Rich & Nutty</p>
            </div>
            <div className="overlay-actions">
              <button className="coll-btn-cart" onClick={(e) => handleQuickAdd(e, 'kaju-jaggery')}>+ Cart</button>
              <button className="coll-btn-buy" onClick={(e) => handleBuyNow(e, 'kaju-jaggery')}>Buy Now</button>
            </div>
          </div>
        </Link>

        <Link to="/product/desi-gud" className="collection-card gud" style={{ textDecoration: 'none' }}>
          <img src="/images/desi-gud.png" alt="Desi Gud" className="collection-img" />
          <div className="collection-text-overlay">
            <div className="overlay-info">
              <h3>Desi Gud</h3>
              <p>Pure Sugarcane</p>
            </div>
            <div className="overlay-actions">
              <button className="coll-btn-cart" onClick={(e) => handleQuickAdd(e, 'desi-gud')}>+ Cart</button>
              <button className="coll-btn-buy" onClick={(e) => handleBuyNow(e, 'desi-gud')}>Buy Now</button>
            </div>
          </div>
        </Link>

        {/* Wide Card Layout */}
        <Link to="/product/jaggery-powder" className="collection-card card-wide" style={{ textDecoration: 'none' }}>
          <img src="/images/jaggery-powder.png" alt="Jaggery Powder" className="collection-img" />
          <div className="collection-text-overlay">
            <div className="overlay-info">
              <h3>Jaggery Powder</h3>
              <p>Fine texture alternative</p>
            </div>
            <div className="overlay-actions">
              <button className="coll-btn-cart" onClick={(e) => handleQuickAdd(e, 'jaggery-powder')}>+ Cart</button>
              <button className="coll-btn-buy" onClick={(e) => handleBuyNow(e, 'jaggery-powder')}>Buy Now</button>
            </div>
          </div>
        </Link>
      </div>
    </section>
  );
};

export default React.memo(Collection);
